const r=(n,p=2)=>Number(n).toFixed(p).replace(/\.0+$/,'').replace(/(\.\d*?)0+$/,'$1');
export function generateSvg(model,exportConfig){const {width,height,layers}=model;let wmm=exportConfig.widthMm,hmm=exportConfig.keepAspect?r(exportConfig.widthMm*height/width,2):exportConfig.heightMm;const color=l=>exportConfig.allBlack?'#000':l.color;let out=`<svg xmlns="http://www.w3.org/2000/svg" width="${wmm}mm" height="${hmm}mm" viewBox="0 0 ${width} ${height}">\n`;if(exportConfig.metadata)out+=`<metadata>Generated by HatchForge: vector hatching only, no embedded raster.</metadata>\n`;for(const l of layers.filter(Boolean)){out+=`<g id="${l.id}" stroke="${color(l)}" fill="none" stroke-width="${l.strokeWidth}" stroke-linecap="${l.lineCap||'round'}" stroke-linejoin="${l.lineJoin||'round'}">\n`;for(const p of l.polylines||[])if(p.length>1)out+=`<path d="M ${p.map(pt=>`${r(pt.x)} ${r(pt.y)}`).join(' L ')}"/>\n`;for(const s of l.segments||[])out+=`<path d="M ${r(s.x1)} ${r(s.y1)} L ${r(s.x2)} ${r(s.y2)}"/>\n`;out+=`</g>\n`}return out+'</svg>\n'}
export function downloadFile(filename,text,type='image/svg+xml'){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type}));a.download=filename;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}
